125	/// Hash function for cutlass::gemm::GemmCoord
126	struct HashGemmCoord {
127	  size_t operator()(cutlass::gemm::GemmCoord const &problem) const {
128	    std::hash<int> hasher;
129	    return (hasher(problem.m() * 3)) ^ (hasher(1 + problem.n() * 5)) ^ (hasher(2 + problem.k() * 7));
130	  }
131	};
