135	// Command line options parsing
136	struct Options {
137	
138	  bool help;
139	  bool error;
140	  bool reference_check;
141	  bool profile_initialization;
142	  bool sort_problems;
143	
144	  std::vector<cutlass::gemm::GemmCoord> problem_sizes;
145	
146	  // problem size bins
147	  std::unordered_map<
148	    cutlass::gemm::GemmCoord,
149	    std::vector<int32_t>,
150	    HashGemmCoord> problem_bins;
151	
152	  int alignment;
153	  int problem_count;
154	  int iterations;
155	  int cuda_streams;
156	  bool verbose;
157	  float alpha;
158	  float beta;
159	  std::string benchmark_path;
160	
161	  std::string   output_tag;
162	  std::ofstream output_file;
163	
164	  using GroupScheduleMode = cutlass::gemm::kernel::GroupScheduleMode;
165	  std::vector<GroupScheduleMode> scheduler_modes;
166	
167	  std::unordered_map<std::string, GroupScheduleMode>
168	    str_to_scheduler_mode = {
169	      {"kDeviceOnly", GroupScheduleMode::kDeviceOnly},
170	      {"kHostPrecompute", GroupScheduleMode::kHostPrecompute}
171	    };
172	
173	  struct GroupScheduleModeHash {
174	    size_t operator()(GroupScheduleMode m) const {
175	      return static_cast<size_t>(m);
176	    }
177	  };
178	
179	  std::unordered_map<GroupScheduleMode, std::string, GroupScheduleModeHash>
180	    scheduler_mode_to_str = {
181	      {GroupScheduleMode::kDeviceOnly, "kDeviceOnly"},
182	      {GroupScheduleMode::kHostPrecompute, "kHostPrecompute"}
183	    };
184	
185	  std::vector<GroupScheduleMode> all_scheduler_modes = {GroupScheduleMode::kDeviceOnly, GroupScheduleMode::kHostPrecompute};
186	
187	  //
188	  // Methods
189	  //
190	
191	  Options():
192	    help(false),
193	    error(false),
194	    alignment(8),
195	    reference_check(true),
196	    profile_initialization(false),
197	    sort_problems(false),
198	    problem_count(15),
199	    iterations(20),
200	    cuda_streams(0),
201	    verbose(false),
202	    alpha(1),
203	    beta(),
204	    scheduler_modes({GroupScheduleMode::kDeviceOnly})
205	  { }
