207	  // Parses the command line
208	  void parse(int argc, char const **args) {
209	    cutlass::CommandLine cmd(argc, args);
210	
211	    if (cmd.check_cmd_line_flag("help")) {
212	      help = true;
213	      return;
214	    }
215	
216	    cmd.get_cmd_line_argument("alignment", alignment, 8);
217	    cmd.get_cmd_line_argument("groups", problem_count, 15);
218	    cmd.get_cmd_line_argument("alpha", alpha, 1.0f);
219	    cmd.get_cmd_line_argument("beta", beta, 0.0f);
220	    cmd.get_cmd_line_argument("iterations", iterations, 20);
221	    cmd.get_cmd_line_argument("streams", cuda_streams, 0);
222	    cmd.get_cmd_line_argument("verbose", verbose, false);
223	    cmd.get_cmd_line_argument("reference-check", reference_check, true);
224	    cmd.get_cmd_line_argument("profile-initialization", profile_initialization, false);
225	    cmd.get_cmd_line_argument("sort-problems", sort_problems, false);
226	    cmd.get_cmd_line_argument("benchmark", benchmark_path);
227	
228	    std::vector<std::string> scheduler_mode_strs;
229	    cmd.get_cmd_line_arguments("scheduler-modes", scheduler_mode_strs);
230	
231	    if (!scheduler_mode_strs.empty()) {
232	      scheduler_modes.clear();
233	      if (scheduler_mode_strs.size() == 1 && scheduler_mode_strs[0] == "all") {
234	        scheduler_modes = all_scheduler_modes;
235	      } else {
236	        for (std::string precomp_str : scheduler_mode_strs) {
237	          auto it = str_to_scheduler_mode.find(precomp_str);
238	          if (it != str_to_scheduler_mode.end()) {
239	            scheduler_modes.push_back(it->second);
240	          } else if (precomp_str == "all") {
241	            std::cerr << "Flag --scheduler-modes=all must not contain other scheduler modes in list." << std::endl;
242	            error = true;
243	            return;
244	          } else {
245	            std::cerr << "Unrecognized scheduler mode '" << precomp_str << "'" << std::endl;
246	            error = true;
247	            return;
248	          }
249	        }
250	      }
251	    }
252	
253	    std::string output_path;
254	    cmd.get_cmd_line_argument("tag", output_tag);
255	    cmd.get_cmd_line_argument("output_file", output_path);
256	
257	    if (!output_path.empty()) {
258	
259	      std::ios_base::openmode open_mode = std::ios_base::out;
260	
261	      std::ifstream input_file(output_path.c_str());
262	
263	      if (input_file.good()) {
264	        open_mode = std::ios_base::app;
265	        input_file.close();
266	      }
267	
268	      output_file.open(output_path.c_str(), open_mode);
269	
270	      if (output_file.good() && open_mode != std::ios_base::app) {
271	        output_file << "Tag,Provider,Kind,Groups,Runtime,GFLOPs\n";
272	      }
273	    }
274	
275	    // Decide how to initialize the problems
276	    if (!benchmark_path.empty()) {
277	      if (!benchmark_problems()) {
278	        error = true;
279	        problem_sizes.clear();
280	        return;
281	      }
282	    }
283	    else {
284	      randomize_problems(cmd);
285	    }
286	
287	    // Post-process the problem sizes
288	    bin_problems();
289	  }
290	
291	  void randomize_problems(cutlass::CommandLine &cmd) {
292	
293	    //
294	    // For now, randomly choose the problem sizes.
295	    //
296	
297	    int cmd_line_m = -1;
298	    int cmd_line_n = -1;
299	    int cmd_line_k = -1;
300	
301	    cmd.get_cmd_line_argument("m", cmd_line_m);
302	    cmd.get_cmd_line_argument("n", cmd_line_n);
303	    cmd.get_cmd_line_argument("k", cmd_line_k);
304	
305	    problem_sizes.reserve(problem_count);
306	
307	    for (int i = 0; i < problem_count; ++i) {
308	
309	      int m = cmd_line_m;
310	      int n = cmd_line_n;
311	      int k = cmd_line_k;
312	
313	      if (m < 1) {
314	        m = alignment * ((rand() % 256) + 1);
315	      }
316	
317	      if (n < 1) {
318	        n = alignment * ((rand() % 256) + 1);
319	      }
320	
321	      if (k < 1) {
322	        k = alignment * ((rand() % 256) + 1);
323	      }
324	
325	      cutlass::gemm::GemmCoord problem(m, n, k);
326	
327	      problem_sizes.push_back(problem);
328	    }
329	  }
