331	  /// Load a benchmark
332	  bool benchmark_problems() {
333	    std::ifstream file(benchmark_path);
334	    if (!file.good()) {
335	      return false;
336	    }
337	
338	    while (file.good()) {
339	
340	      int idx = -1;
341	      std::string extent_str;
342	
343	      file >> idx >> extent_str;
344	
345	      if (idx < 0 || extent_str.empty()) {
346	        break;
347	      }
348	
349	      cutlass::gemm::GemmCoord extent;
350	      std::vector<std::string> tokens;
351	
352	      cutlass::CommandLine::tokenize(tokens, extent_str, 'x');
353	
354	      for (int i = 0; i < int(tokens.size()); ++i) {
355	        int x = std::atoi(tokens.at(i).c_str());
356	
357	        // round up
358	        if (x % alignment) {
359	          x += (alignment - (x % alignment));
360	        }
361	
362	        extent.at(i) = x;
363	      }
364	
365	      if (extent.product()) {
366	        problem_sizes.push_back(extent);
367	      }
368	    }
369	
370	    return true;
371	  }
372	
373	  /// Post processes the problems
374	  void bin_problems() {
375	
376	    problem_bins.clear();
377	
378	    problem_count = int(problem_sizes.size());
379	
380	    //
381	    // Insert the problem sizes into a sorted container class. This is *NOT* necessary
382	    // to run the CUTLASS kernel, but it enables the execution of cublas's batched GEMM.
383	    //
384	    for (int i = 0; i < int(problem_sizes.size()); ++i) {
385	      auto it = problem_bins.find(problem_sizes.at(i));
386	      if (it == problem_bins.end()) {
387	        problem_bins.insert({problem_sizes.at(i), std::vector<int32_t>({i}) });
388	      }
389	      else {
390	        it->second.push_back(i);
391	      }
392	    }
393	  }
