454	
455	  /// Compute performance in GFLOP/s
456	  double gflops(double runtime_s) const {
457	
458	    // Number of real-valued multiply-adds
459	    int64_t fmas = int64_t();
460	
461	    for (auto const & problem : problem_sizes) {
462	      fmas += problem.product();
463	    }
464	
465	    // Two flops per multiply-add
466	    return 2.0 * double(fmas) / double(1.0e9) / runtime_s;
467	  }
468	};
