545	  /// Helper to initialize a tensor view
546	  template <typename Element>
547	  void initialize_tensor(
548	    Element *ptr,
549	    size_t capacity,
550	    cutlass::Distribution::Kind dist_kind,
551	    uint32_t seed) {
552	
553	    if (dist_kind == cutlass::Distribution::Uniform) {
554	
555	      Element scope_max, scope_min;
556	      int bits_input = cutlass::sizeof_bits<Element>::value;
557	      int bits_output = cutlass::sizeof_bits<typename Gemm::ElementC>::value;
558	
559	      if (bits_input == 1) {
560	        scope_max = 2;
561	        scope_min = 0;
562	      } else if (bits_input <= 8) {
563	        scope_max = 2;
564	        scope_min = -2;
565	      } else if (bits_output == 16) {
566	        if (cutlass::sizeof_bits<ElementAccumulator>::value <= 16) {
567	          scope_max = 5;
568	          scope_min = -5;
569	        }
570	        else {
571	          scope_max = 8;
572	          scope_min = -8;
573	        }
574	      } else {
575	        scope_max = 8;
576	        scope_min = -8;
577	      }
578	
579	      cutlass::reference::device::BlockFillRandomUniform(
580	        ptr, capacity, seed, scope_max, scope_min, 0);
581	    }
582	    else if (dist_kind == cutlass::Distribution::Gaussian) {
583	
584	      cutlass::reference::device::BlockFillRandomGaussian(
585	        ptr, capacity, seed, Element(), Element(0.5f));
586	    }
587	    else if (dist_kind == cutlass::Distribution::Sequential) {
588	
589	      // Fill with increasing elements
590	      cutlass::reference::device::BlockFillSequential(
591	        ptr, capacity, Element(1), Element());
592	    }
593	    else {
594	
595	      // Fill with all 1s
596	      cutlass::reference::device::BlockFillSequential(
597	        ptr, capacity, Element(), Element(1));
598	    }
599	  }
600	
601	  /// Allocates device-side data
602	  void allocate() {
603	    int64_t total_elements_A = 0;
604	    int64_t total_elements_B = 0;
605	    int64_t total_elements_C = 0;
606	    int64_t total_elements_D = 0;
607	
608	    lda_host.resize(problem_count());
609	    ldb_host.resize(problem_count());
610	    ldc_host.resize(problem_count());
611	    ldd_host.resize(problem_count());
612	
613	    for (int32_t i = 0; i < problem_count(); ++i) {
614	
615	      auto problem = options.problem_sizes.at(i);
616	
617	      lda_host.at(i) = LayoutA::packed({problem.m(), problem.k()}).stride(0);
618	      ldb_host.at(i) = LayoutB::packed({problem.k(), problem.n()}).stride(0);
619	      ldc_host.at(i) = LayoutC::packed({problem.m(), problem.n()}).stride(0);
620	      ldd_host.at(i) = LayoutC::packed({problem.m(), problem.n()}).stride(0);
621	
622	      offset_A.push_back(total_elements_A);
623	      offset_B.push_back(total_elements_B);
624	      offset_C.push_back(total_elements_C);
625	      offset_D.push_back(total_elements_D);
626	
627	      int64_t elements_A = problem.m() * problem.k();
628	      int64_t elements_B = problem.k() * problem.n();
629	      int64_t elements_C = problem.m() * problem.n();
630	      int64_t elements_D = problem.m() * problem.n();
631	
632	      total_elements_A += elements_A;
633	      total_elements_B += elements_B;
634	      total_elements_C += elements_C;
635	      total_elements_D += elements_D;
636	    }
637	
638	    lda.reset(problem_count());
639	    ldb.reset(problem_count());
640	    ldc.reset(problem_count());
641	    ldd.reset(problem_count());
642	
643	    block_A.reset(total_elements_A);
644	    block_B.reset(total_elements_B);
645	    block_C.reset(total_elements_C);
646	    block_D.reset(total_elements_D);
647	  }
648	
649	  /// Initializes device-side data
650	  void initialize() {
651	    problem_sizes_device.reset(problem_count());
652	    problem_sizes_device.copy_from_host(options.problem_sizes.data());
653	
654	    lda.copy_from_host(lda_host.data());
655	    ldb.copy_from_host(ldb_host.data());
656	    ldc.copy_from_host(ldc_host.data());
657	    ldd.copy_from_host(ldd_host.data());
658	
659	    //
660	    // Assign pointers
661	    //
662	
663	    std::vector<ElementA *> ptr_A_host(problem_count());
664	    std::vector<ElementB *> ptr_B_host(problem_count());
665	    std::vector<ElementC *> ptr_C_host(problem_count());
666	    std::vector<ElementC *> ptr_D_host(problem_count());
667	
668	    for (int32_t i = 0; i < problem_count(); ++i) {
669	      ptr_A_host.at(i) = block_A.get() + offset_A.at(i);
670	      ptr_B_host.at(i) = block_B.get() + offset_B.at(i);
671	      ptr_C_host.at(i) = block_C.get() + offset_C.at(i);
672	      ptr_D_host.at(i) = block_D.get() + offset_D.at(i);
673	    }
674	
675	    ptr_A.reset(problem_count());
676	    ptr_A.copy_from_host(ptr_A_host.data());
677	
678	    ptr_B.reset(problem_count());
679	    ptr_B.copy_from_host(ptr_B_host.data());
680	
681	    ptr_C.reset(problem_count());
682	    ptr_C.copy_from_host(ptr_C_host.data());
683	
684	    ptr_D.reset(problem_count());
685	    ptr_D.copy_from_host(ptr_D_host.data());
686	
687	    //
688	    // Initialize the problems of the workspace
689	    //
690	
691	    initialize_tensor(block_A.get(), block_A.size(), init_A, seed * 2021);
692	    initialize_tensor(block_B.get(), block_B.size(), init_B, seed * 2022);
693	    initialize_tensor(block_C.get(), block_C.size(), init_C, seed * 2023);
694	
695	    cutlass::reference::device::BlockFillSequential(
696	      block_D.get(), block_D.size(), ElementC(), ElementC());
697	  }
698	
699	  /// Verifies the result is a GEMM
700	  bool verify() {
701	
702	    bool passed = true;
703	
704	    for (int32_t i = 0; i < problem_count(); ++i) {
705	      cutlass::gemm::GemmCoord problem = options.problem_sizes.at(i);
706	
707	      LayoutA layout_A(lda_host.at(i));
708	      LayoutB layout_B(ldb_host.at(i));
709	      LayoutC layout_C(ldc_host.at(i));
710	      LayoutC layout_D(ldd_host.at(i));
711	
712	      MatrixCoord extent_A{problem.m(), problem.k()};
713	      MatrixCoord extent_B{problem.k(), problem.n()};
714	      MatrixCoord extent_C{problem.m(), problem.n()};
715	
716	      cutlass::TensorView<ElementA, LayoutA> view_A(block_A.get() + offset_A.at(i), layout_A, extent_A);
717	      cutlass::TensorView<ElementB, LayoutB> view_B(block_B.get() + offset_B.at(i), layout_B, extent_B);
718	      cutlass::TensorView<ElementC, LayoutC> view_C(block_C.get() + offset_C.at(i), layout_C, extent_C);
719	
720	      cutlass::DeviceAllocation<ElementC>    block_Ref(layout_D.capacity(extent_C));
721	      cutlass::TensorView<ElementC, LayoutC> view_Ref_device(block_Ref.get(), layout_D, extent_C);
722	
723	      // Reference GEMM
724	      cutlass::reference::device::GemmComplex<
725	          ElementA, LayoutA,
726	          ElementB, LayoutB,
727	          ElementC, LayoutC,
728	          ElementCompute, ElementAccumulator
729	      >(
730	        problem,
731	        options.alpha,
732	        view_A,
733	        Gemm::kTransformA,
734	        view_B,
735	        Gemm::kTransformB,
736	        options.beta,
737	        view_C,
738	        view_Ref_device,
739	        ElementAccumulator(0)
740	      );
741	
742	      // Copy to host memory
743	      std::vector<ElementC> matrix_D(layout_D.capacity(extent_C));
744	      std::vector<ElementC> matrix_Ref(layout_D.capacity(extent_C));
745	
746	      cutlass::device_memory::copy_to_host(matrix_D.data(),   block_D.get() + offset_D.at(i), matrix_D.size());
747	      cutlass::device_memory::copy_to_host(matrix_Ref.data(), block_Ref.get(),                matrix_D.size());
748	
749	      cutlass::TensorView<ElementC, LayoutC> view_D(  matrix_D.data(),   layout_D, extent_C);
750	      cutlass::TensorView<ElementC, LayoutC> view_Ref(matrix_Ref.data(), layout_D, extent_C);
751	
752	      // Reference check
753	      passed = cutlass::reference::host::TensorEquals(view_D, view_Ref);
754	
755	      if (!passed) {
756	        std::cerr << "\n***\nError - problem " << i << " failed the QA check\n***\n" << std::endl;
757	        return passed;
758	      }
759	    }
760	
761	    return passed;
762	  }
763	
764	};
