799	  /// Executes a batched kernel and measures runtime
800	  Result profile() {
801	    std::cout << "Batched GEMM:\n"
802	      << "====================================================" << std::endl;
803	
804	    Result result;
805	    result.passed = false;
806	
807	    // Initialize the problem
808	    this->allocate();
809	    this->initialize();
810	
811	    if (this->options.verbose) {
812	      print_problem_sizes();
813	    }
814	
815	    //
816	    // Prepare batched GEMM environment
817	    //
818	
819	    int32_t effective_streams = (this->options.cuda_streams ? this->options.cuda_streams : 1);
820	
821	    // Array of leading dimensions used by batched GEMM calls
822	    std::vector<cutlass::gemm::GemmCoord> bin_problem_sizes;
823	    std::vector<int32_t>                  bin_count;
824	    std::vector<int32_t>                  bin_ldm_A;
825	    std::vector<int32_t>                  bin_ldm_B;
826	    std::vector<int32_t>                  bin_ldm_C;
827	    std::vector<int32_t>                  bin_start;
828	
829	    std::vector<void const *> ptr_A_batched_host;
830	    std::vector<void const *> ptr_B_batched_host;
831	    std::vector<void       *> ptr_C_batched_host;
832	
833	    for (auto const & bin : this->options.problem_bins) {
834	      int first_idx = bin.second.front();
835	
836	      bin_problem_sizes.push_back(this->options.problem_sizes.at(first_idx));
837	      bin_count.push_back(int32_t(bin.second.size()));
838	
839	      bin_ldm_A.push_back(static_cast<int32_t>(this->lda_host.at(first_idx)));
840	      bin_ldm_B.push_back(static_cast<int32_t>(this->ldb_host.at(first_idx)));
841	      bin_ldm_C.push_back(static_cast<int32_t>(this->ldc_host.at(first_idx)));
842	
843	      if (ptr_A_batched_host.size() % 2) {
844	        ptr_A_batched_host.push_back(nullptr);
845	        ptr_B_batched_host.push_back(nullptr);
846	        ptr_C_batched_host.push_back(nullptr);
847	      }
848	
849	      bin_start.push_back(int32_t(ptr_A_batched_host.size()));
850	
851	      for (int idx : bin.second) {
852	
853	        if (bin_problem_sizes.back() != this->options.problem_sizes.at(idx)) {
854	          std::cerr << "Error - failed to group problems.\n";
855	          return result;
856	        }
857	
858	        if (bin_ldm_A.back() != this->lda_host.at(idx)) {
859	          std::cerr << "Error - failed to group problems.\n";
860	          return result;
861	        }
862	
863	        if (bin_ldm_B.back() != this->ldb_host.at(idx)) {
864	          std::cerr << "Error - failed to group problems.\n";
865	          return result;
866	        }
867	
868	        if (bin_ldm_C.back() != this->ldc_host.at(idx)) {
869	          std::cerr << "Error - failed to group problems.\n";
870	          return result;
871	        }
872	
873	        ptr_A_batched_host.push_back(this->block_A.get() + this->offset_A.at(idx));
874	        ptr_B_batched_host.push_back(this->block_B.get() + this->offset_B.at(idx));
875	        ptr_C_batched_host.push_back(this->block_D.get() + this->offset_C.at(idx));
876	      }
877	    }
878	
879	    // Array of GMEM pointers used by batched array GEMM calls
880	    cutlass::DeviceAllocation<void const *> ptr_A_batched;
881	    cutlass::DeviceAllocation<void const *> ptr_B_batched;
882	    cutlass::DeviceAllocation<void       *> ptr_C_batched;
883	
884	    ptr_A_batched.reset(ptr_A_batched_host.size());
885	    ptr_B_batched.reset(ptr_A_batched_host.size());
886	    ptr_C_batched.reset(ptr_A_batched_host.size());
887	
888	    ptr_A_batched.copy_from_host(ptr_A_batched_host.data());
889	    ptr_B_batched.copy_from_host(ptr_B_batched_host.data());
890	    ptr_C_batched.copy_from_host(ptr_C_batched_host.data());
891	
892	    //
893	    // Create CUDA streams to maximize concurrency of batched-array GEMM kernels
894	    //
895	    std::vector<cudaStream_t>   cuda_streams;
896	
897	    //
898	    // Warmup run
899	    //
900	
901	
902	    if (this->options.cuda_streams) {
903	      for (int i = 0; i < this->options.cuda_streams; ++i) {
904	        cudaStream_t stream;
905	
906	        result.error = cudaStreamCreate(&stream);
907	        if (result.error != cudaSuccess) {
908	        std::cerr << "Failed to create CUDA stream." << std::endl;
909	          return result;
910	        }
911	        cuda_streams.push_back(stream);
912	
913	      }
914	    }
915	    else {
916	      cuda_streams.push_back(nullptr);
917	
918	    }
919	
920	    // Use 'D' for the in/out workspace
921	    this->block_D.copy_from_device(this->block_C.get());
922	
923	    for (int bin_idx = 0; bin_idx < int32_t(bin_problem_sizes.size()); ++bin_idx) {
924	
925	      cutlass::gemm::GemmCoord const & problem = bin_problem_sizes[bin_idx];
926	      int32_t batch_count = bin_count[bin_idx];
927	      int32_t bin_start_idx = bin_start[bin_idx];
928	      int32_t lda = bin_ldm_A[bin_idx];
929	      int32_t ldb = bin_ldm_B[bin_idx];
930	      int32_t ldc = bin_ldm_C[bin_idx];
931	
932	      void const ** ptr_A_array = ptr_A_batched.get() + bin_start[bin_idx];
933	      void const ** ptr_B_array = ptr_B_batched.get() + bin_start[bin_idx];
934	      void       ** ptr_C_array = ptr_C_batched.get() + bin_start[bin_idx];
935	
936	      //
937	      // Initialize the CUTLASS GEMM operator
938	      //
939	
940	      // Configure the GEMM arguments
941	      typename Gemm::EpilogueOutputOp::Params epilogue_op(this->options.alpha, this->options.beta);
942	
943	      typename Gemm::Arguments arguments{
944	        cutlass::gemm::GemmUniversalMode::kArray,
945	        problem,
946	        batch_count,
947	        epilogue_op,
948	        (void const *)ptr_A_array,
949	        (void const *)ptr_B_array,
950	        (void const *)ptr_C_array,
951	        (void       *)ptr_C_array,
952	        int64_t(),
953	        int64_t(),
954	        int64_t(),
955	        int64_t(),
956	        int64_t(lda),
957	        int64_t(ldb),
958	        int64_t(ldc),
959	        int64_t(ldc)
960	      };
961	
962	      Gemm gemm_op;
963	
964	      cutlass::Status status = gemm_op.initialize(arguments);
965	
966	      if (status != cutlass::Status::kSuccess) {
967	        std::cerr << "CUTLASS error on line " << __LINE__ << std::endl;
968	        return result;
969	      }
970	
971	      status = gemm_op();
972	
973	      if (status != cutlass::Status::kSuccess) {
974	        std::cerr << "CUTLASS error on line " << __LINE__ << std::endl;
975	        return result;
976	      }
977	
978	    }
979	
980	    //
981	    // Wait for completion
982	    //
983	
984	    result.error = cudaDeviceSynchronize();
985	
986	    if (result.error != cudaSuccess)  {
987	      std::cerr << "Kernel execution error: " << cudaGetErrorString(result.error);
988	      return result;
989	    }
990	
991	    //
992	    // Construct events
993	    //
994	
995	    cudaEvent_t events[2];
996	
997	    for (auto & event : events) {
998	      result.error = cudaEventCreate(&event);
999	      if (result.error != cudaSuccess) {
1000	        std::cerr << "cudaEventCreate() failed: " << cudaGetErrorString(result.error) << std::endl;
1001	        return -1;
1002	      }
1003	    }
1004	
1005	    //
1006	    // Wait for completion
1007	    //
1008	
1009	    result.error = cudaDeviceSynchronize();
1010	
1011	    if (result.error != cudaSuccess)  {
1012	      std::cerr << "Kernel execution error: " << cudaGetErrorString(result.error);
1013	      return result;
1014	    }
1015	
1016	    // Record an event at the start of a series of GEMM operations
1017	    result.error = cudaEventRecord(events[0]);
1018	    if (result.error != cudaSuccess) {
1019	      std::cerr << "cudaEventRecord() failed: " << cudaGetErrorString(result.error) << std::endl;
1020	      return result;
1021	    }
1022	
1023	    //
1024	    // Run profiling loop
1025	    //
1026	
1027	    int last_stream_idx = 0;
1028	
1029	    for (int iter = 0; iter < this->options.iterations; ++iter) {
1030	
1031	      for (int bin_idx = 0; bin_idx < int32_t(bin_problem_sizes.size()); ++bin_idx) {
1032	
1033	        cutlass::gemm::GemmCoord const & problem = bin_problem_sizes[bin_idx];
1034	        int32_t batch_count = bin_count[bin_idx];
1035	        int32_t bin_start_idx = bin_start[bin_idx];
1036	        int32_t lda = bin_ldm_A[bin_idx];
1037	        int32_t ldb = bin_ldm_B[bin_idx];
1038	        int32_t ldc = bin_ldm_C[bin_idx];
1039	
1040	        void const ** ptr_A_array = ptr_A_batched.get() + bin_start[bin_idx];
1041	        void const ** ptr_B_array = ptr_B_batched.get() + bin_start[bin_idx];
1042	        void       ** ptr_C_array = ptr_C_batched.get() + bin_start[bin_idx];
1043	
1044	        last_stream_idx = (bin_idx % effective_streams);
1045	
1046	        //
1047	        // Initialize the CUTLASS GEMM operator
1048	        //
1049	
1050	        // Configure the GEMM arguments
1051	        typename Gemm::EpilogueOutputOp::Params epilogue_op(this->options.alpha, this->options.beta);
1052	
1053	        typename Gemm::Arguments arguments{
1054	          cutlass::gemm::GemmUniversalMode::kArray,
1055	          problem,
1056	          batch_count,
1057	          epilogue_op,
1058	          (void const *)ptr_A_array,
1059	          (void const *)ptr_B_array,
1060	          (void const *)ptr_C_array,
1061	          (void       *)ptr_C_array,
1062	          int64_t(),
1063	          int64_t(),
1064	          int64_t(),
1065	          int64_t(),
1066	          int64_t(lda),
1067	          int64_t(ldb),
1068	          int64_t(ldc),
1069	          int64_t(ldc)
1070	        };
1071	
1072	        Gemm gemm_op;
1073	
1074	        cutlass::Status status = gemm_op.initialize(arguments);
1075	
1076	        if (status != cutlass::Status::kSuccess) {
1077	          std::cerr << "CUTLASS error on line " << __LINE__ << std::endl;
1078	          return result;
1079	        }
1080	
1081	        status = gemm_op(cuda_streams[last_stream_idx]);
1082	
1083	        if (status != cutlass::Status::kSuccess) {
1084	          std::cerr << "CUTLASS error on line " << __LINE__ << std::endl;
1085	          return result;
1086	        }
1087	
1088	      }
1089	    }
1090	
1091	    //
1092	    // Stop profiling loop
1093	    //
1094	
1095	    // Record an event when the GEMM operations have been launched.
1096	    result.error = cudaEventRecord(events[1]);
1097	    if (result.error != cudaSuccess) {
1098	      std::cerr << "cudaEventRecord() failed: " << cudaGetErrorString(result.error) << std::endl;
1099	      return result;
1100	    }
1101	
1102	    //
1103	    // Wait for work to be completed
1104	    //
1105	
1106	    result.error = cudaDeviceSynchronize();
1107	
1108	    if (result.error != cudaSuccess)  {
1109	      std::cerr << "Kernel execution error: " << cudaGetErrorString(result.error);
1110	      return result;
1111	    }
1112	
1113	    // Measure elapsed runtime
1114	    float runtime_ms = 0;
1115	    result.error = cudaEventElapsedTime(&runtime_ms, events[0], events[1]);
1116	    if (result.error != cudaSuccess) {
1117	      std::cerr << "cudaEventElapsed() failed: " << cudaGetErrorString(result.error) << std::endl;
1118	      return result;
1119	    }
1120	
1121	    // Compute average runtime and GFLOPs.
1122	    result.runtime_ms = double(runtime_ms) / double(this->options.iterations);
1123	    result.gflops = this->options.gflops(result.runtime_ms / 1000.0);
1124	
1125	    //
1126	    // Cleanup
1127	    //
1128	
1129	    for (auto event : events) {
1130	      (void)cudaEventDestroy(event);
1131	    }
1132	
1133	    for (auto stream : cuda_streams) {
1134	      if (stream) {
1135	        (void)cudaStreamDestroy(stream);
1136	      }
1137	    }
1138	
1139	    std::cout << "    " << this->options.problem_bins.size() << " batched GEMMs launched" << std::endl;
1140	    std::cout << std::endl;
1141	    std::cout << "    " << "Batched Runtime: " << result.runtime_ms << " ms" << std::endl;
1142	    std::cout << "    " << "Batched  GFLOPs: " << result.gflops << std::endl;
1143	
1144	    std::string provider = "CUTLASS";
1145	
1146	    if (this->options.output_file.good()) {
1147	      this->options.output_file << this->options.output_tag << "," << provider << ",batched,"
1148	        << this->options.problem_count << "," << result.runtime_ms << "," << result.gflops << std::endl;
1149	    }
1150	
1151	    result.passed = true;
1152	    return result;
1153	  }
1154	};
