1160	    Options &options_,
1161	    cutlass::Distribution::Kind init_A_ = cutlass::Distribution::Uniform,
1162	    cutlass::Distribution::Kind init_B_ = cutlass::Distribution::Uniform,
1163	    cutlass::Distribution::Kind init_C_ = cutlass::Distribution::Uniform,
1164	    uint32_t seed_ = 3080
1165	  ): BaseTestbed<Gemm_>(options_, init_A_, init_B_, init_C_, seed_) {}
1166	
1167	  // Redefine GEMM with different GroupScheduleMode_
1168	  using GemmKernel = typename cutlass::gemm::kernel::DefaultGemmGrouped<
1169	    typename Gemm_::ElementA,
1170	    typename Gemm_::LayoutA,
1171	    Gemm_::kTransformA,
1172	    Gemm_::kAlignmentA,
1173	    typename Gemm_::ElementB,
1174	    typename Gemm_::LayoutB,
1175	    Gemm_::kTransformB,
1176	    Gemm_::kAlignmentB,
1177	    typename Gemm_::ElementC,
1178	    typename Gemm_::LayoutC,
1179	    typename Gemm_::ElementAccumulator,
1180	    typename Gemm_::OperatorClass,
1181	    typename Gemm_::ArchTag,
1182	    typename Gemm_::ThreadblockShape,
1183	    typename Gemm_::WarpShape,
1184	    typename Gemm_::InstructionShape,
1185	    typename Gemm_::EpilogueOutputOp,
1186	    typename Gemm_::ThreadblockSwizzle,
1187	    Gemm_::kStages,
1188	    GroupScheduleMode_>::GemmKernel;
1189	
1190	  using Gemm = cutlass::gemm::device::GemmGrouped<GemmKernel>;
1191	
1192	  /// Verbose printing of problem sizes
1193	  void print_problem_sizes() {
1194	    std::cout << std::endl;
1195	
1196	    // Print groups
1197	    std::cout << this->problem_count() << " groups:\n";
1198	
1199	    int32_t idx = 0;
1200	    int64_t total_tiles = 0;
1201	
1202	    for (auto const & problem : this->options.problem_sizes) {
1203	      int tiles = Gemm::problem_tile_count(problem);
1204	      total_tiles += tiles;
1205	
1206	      std::cout << "  [" << idx << "]: "
1207	        << problem.m() << "-by-" << problem.n() << "-by-" << problem.k()
1208	        << " (" << tiles << " threadblock tiles)" << "\n";
1209	
1210	      ++idx;
1211	    }
1212	    std::cout << std::endl;
1213	  }
1214	
1215	  /// Sort problems in descending order of problem-K dimension
1216	  void sort_problems() {
1217	    Gemm::sort_problems(this->options.problem_count,
1218	                        this->options.problem_sizes.data(),
1219	                        this->lda_host.data(),
1220	                        this->ldb_host.data(),
1221	                        this->ldc_host.data(),
1222	                        this->ldd_host.data(),
1223	                        this->offset_A.data(),
1224	                        this->offset_B.data(),
1225	                        this->offset_C.data(),
1226	                        this->offset_D.data());
1227	  }
1228	
1229	  /// Executes a grouped kernel and measures runtime
1230	  Result profile() {
1231	    std::string sched_mode = this->options.scheduler_mode_to_str.find(GroupScheduleMode_)->second;
1232	
1233	    std::cout << std::endl;
1234	    std::cout << "Grouped GEMM (CUTLASS) with mode " << sched_mode << ":\n"
1235	      << "====================================================" << std::endl;
1236	
1237	    Result result;
1238	
1239	    int threadblock_count = Gemm::sufficient(this->options.problem_sizes.data(), this->options.problem_count);
1240	
1241	    // Early exit
1242	    if (!threadblock_count) {
1243	      std::cout << "Active CUDA device lacks hardware resources to run CUTLASS Grouped GEMM kernel." << std::endl;
1244	      return result;
1245	    }
1246	
1247	    result.passed = false;
1248	
1249	    // Initialize the problem
1250	    this->allocate();
1251	    if (this->options.sort_problems) {
1252	      sort_problems();
1253	    }
1254	    this->initialize();
1255	
1256	    if (this->options.verbose) {
1257	      print_problem_sizes();
1258	    }
1259	
1260	    // Configure the GEMM arguments
1261	    typename Gemm::EpilogueOutputOp::Params epilogue_op(this->options.alpha, this->options.beta);
1262	
1263	    // Configure GEMM arguments
1264	    typename Gemm::Arguments args(
1265	      this->problem_sizes_device.get(),
1266	      this->problem_count(),
1267	      threadblock_count,
1268	      epilogue_op,
1269	      this->ptr_A.get(),
1270	      this->ptr_B.get(),
1271	      this->ptr_C.get(),
1272	      this->ptr_D.get(),
1273	      this->lda.get(),
1274	      this->ldb.get(),
1275	      this->ldc.get(),
1276	      this->ldd.get(),
1277	      this->options.problem_sizes.data()
1278	    );
1279	
1280	    // Initialize the GEMM object
1281	    Gemm gemm;
1282	
1283	    size_t workspace_size = gemm.get_workspace_size(args);
1284	    cutlass::DeviceAllocation<uint8_t> workspace(workspace_size);
1285	
1286	    result.status = gemm.initialize(args, workspace.get());
1287	
1288	    if (result.status != cutlass::Status::kSuccess) {
1289	      std::cerr << "Failed to initialize CUTLASS Grouped GEMM kernel." << std::endl;
1290	      return result;
1291	    }
1292	
1293	    // Run the grouped GEMM object
1294	    result.status = gemm.run();
1295	
1296	    if (result.status != cutlass::Status::kSuccess) {
1297	      std::cerr << "Failed to run CUTLASS Grouped GEMM kernel." << std::endl;
1298	      return result;
1299	    }
1300	
1301	    // Wait for completion
1302	    result.error = cudaDeviceSynchronize();
1303	
1304	    if (result.error != cudaSuccess)  {
1305	      std::cerr << "Kernel execution error: " << cudaGetErrorString(result.error);
1306	      return result;
1307	    }
1308	
1309	    //
1310	    // Verify correctness
1311	    //
1312	    result.passed = true;
1313	
1314	    if (this->options.reference_check) {
1315	      result.passed = this->verify();
1316	    }
1317	
1318	    //
1319	    // Warm-up run of the grouped GEMM object
1320	    //
1321	    result.status = gemm.run();
1322	
1323	    if (result.status != cutlass::Status::kSuccess) {
1324	      std::cerr << "Failed to run CUTLASS Grouped GEMM kernel." << std::endl;
1325	      return result;
1326	    }
1327	
1328	    //
1329	    // Construct events
1330	    //
1331	
1332	    cudaEvent_t events[2];
1333	
1334	    for (auto & event : events) {
1335	      result.error = cudaEventCreate(&event);
1336	      if (result.error != cudaSuccess) {
1337	        std::cerr << "cudaEventCreate() failed: " << cudaGetErrorString(result.error) << std::endl;
1338	        return -1;
1339	      }
1340	    }
1341	
1342	    // Record an event at the start of a series of GEMM operations
1343	    result.error = cudaEventRecord(events[0]);
1344	    if (result.error != cudaSuccess) {
1345	      std::cerr << "cudaEventRecord() failed: " << cudaGetErrorString(result.error) << std::endl;
1346	      return result;
1347	    }
1348	
1349	    //
1350	    // Run profiling loop
1351	    //
1352	
1353	    for (int iter = 0; iter < this->options.iterations; ++iter) {
1354	      gemm();
1355	    }
1356	
1357	    //
1358	    // Stop profiling loop
1359	    //
1360	
1361	    // Record an event when the GEMM operations have been launched.
1362	    result.error = cudaEventRecord(events[1]);
1363	    if (result.error != cudaSuccess) {
1364	      std::cerr << "cudaEventRecord() failed: " << cudaGetErrorString(result.error) << std::endl;
1365	      return result;
1366	    }
1367	
1368	    // Wait for work on the device to complete.
1369	    result.error = cudaEventSynchronize(events[1]);
1370	    if (result.error != cudaSuccess) {
1371	      std::cerr << "cudaEventSynchronize() failed: " << cudaGetErrorString(result.error) << std::endl;
1372	      return result;
1373	    }
1374	
1375	    // Measure elapsed runtime
1376	    float runtime_ms = 0;
1377	    result.error = cudaEventElapsedTime(&runtime_ms, events[0], events[1]);
1378	    if (result.error != cudaSuccess) {
1379	      std::cerr << "cudaEventElapsed() failed: " << cudaGetErrorString(result.error) << std::endl;
1380	      return result;
1381	    }
1382	
1383	    // Compute average runtime and GFLOPs.
1384	    result.runtime_ms = double(runtime_ms) / double(this->options.iterations);
1385	    result.gflops = this->options.gflops(result.runtime_ms / 1000.0);
1386	
1387	    //
1388	    // Cleanup
1389	    //
1390	
1391	    for (auto event : events) {
1392	      (void)cudaEventDestroy(event);
1393	    }
1394	
1395	    // Optionally profile initialization
1396	    if (this->options.profile_initialization) {
1397	      // Warm up
1398	      gemm.initialize(args, workspace.get());
1399	
1400	      auto start_time = std::chrono::high_resolution_clock::now();
1401	      for (int32_t i = 0; i < this->options.iterations; ++i) {
1402	        gemm.initialize(args, workspace.get());
1403	      }
1404	      auto end_time = std::chrono::high_resolution_clock::now();
1405	
1406	      std::chrono::duration<double, std::milli> duration = end_time - start_time;
1407	      duration /= double(this->options.iterations);
1408	      result.initialization_time_ms = duration.count();
1409	    }
1410	
1411	    int64_t total_tiles = Gemm::group_tile_count(args);
1412	    std::cout << "    " << total_tiles << " total threadblock tiles." << std::endl;
1413	
1414	    std::cout << std::endl;
1415	    std::cout << "    " << "Grouped Runtime: " << result.runtime_ms << " ms" << std::endl;
1416	    std::cout << "    " << "Grouped  GFLOPs: " << result.gflops << std::endl;
1417	    if (this->options.profile_initialization) {
1418	      std::cout << "    " << "Init    Runtime: " << result.initialization_time_ms << " ms" << std::endl;
1419	    }
1420	
1421	    if (this->options.output_file.good()) {
1422	      this->options.output_file << this->options.output_tag << ",CUTLASS,grouped-" << sched_mode << ","
1423	        << this->options.problem_count << "," << result.runtime_ms << "," << result.gflops << std::endl;
1424	    }
1425	
1426	    std::cout << "\nPassed\n";
1427	
1428	    return result;
1429	  }
1430	};
1431	
