1433	
1434	int main(int argc, char const **args) {
1435	
1436	  cudaDeviceProp props;
1437	
1438	  cudaError_t error = cudaGetDeviceProperties(&props, 0);
1439	  if (error != cudaSuccess) {
1440	    std::cerr << "cudaGetDeviceProperties() returned an error: " << cudaGetErrorString(error) << std::endl;
1441	    return -1;
1442	  }
1443	
1444	  if (__CUDACC_VER_MAJOR__ < 11 || props.major < 8) {
1445	
1446	    //
1447	    // This example requires an NVIDIA Ampere-architecture GPU.
1448	    //
1449	
1450	    std::cout
1451	      << "CUTLASS's Grouped GEMM example requires a GPU of NVIDIA's Ampere Architecture or "
1452	      << "later (compute capability 80 or greater).\n";
1453	
1454	    return 0;
1455	  }
1456	
1457	  //
1458	  // Parse options
1459	  //
1460	
1461	  Options options;
1462	
1463	  options.parse(argc, args);
1464	
1465	  if (options.help) {
1466	    options.print_usage(std::cout) << std::endl;
1467	    return 0;
1468	  }
1469	
1470	  if (options.error) {
1471	    std::cerr << "Aborting execution." << std::endl;
1472	    return -1;
1473	  }
1474	
1475	  //
1476	  // Define the Grouped and Batched GEMM types
1477	  //
1478	
1479	  using ElementA = cutlass::half_t;
1480	  using ElementB = cutlass::half_t;
1481	  using ElementOutput = cutlass::half_t;
1482	  using ElementAccumulator = float;
1483	
1484	  using LayoutA = cutlass::layout::ColumnMajor;
1485	  using LayoutB = cutlass::layout::ColumnMajor;
1486	  using LayoutC = cutlass::layout::ColumnMajor;
1487	
1488	  // Gemm operator cutlass_tensorop_f16_s16816gemm_f16_128x128_32x4_nt_align8
1489	  using GemmBatched = cutlass::gemm::device::GemmUniversal<
1490	    ElementA, LayoutA,
1491	    ElementB, LayoutB,
1492	    ElementOutput,   LayoutC,
1493	    ElementAccumulator,
1494	    cutlass::arch::OpClassTensorOp,
1495	    cutlass::arch::Sm80,
1496	    cutlass::gemm::GemmShape<128, 128, 32>,
1497	    cutlass::gemm::GemmShape<64, 64, 32>,
1498	    cutlass::gemm::GemmShape<16, 8, 16>,
1499	    cutlass::epilogue::thread::LinearCombination<
1500	      ElementOutput,
1501	      128 / cutlass::sizeof_bits<ElementOutput>::value,
1502	      ElementAccumulator,
1503	      ElementAccumulator
1504	    >,
1505	    cutlass::gemm::threadblock::GemmIdentityThreadblockSwizzle<8>,
1506	    4
1507	  >;
1508	
1509	  // Define a grouped GEMM kernel with all template parameters set except
1510	  // for scheduling mode. This will be used as the template for all scheduling
1511	  // modes executed.
1512	  using GemmKernel = typename cutlass::gemm::kernel::DefaultGemmGrouped<
1513	    ElementA,
1514	    LayoutA,
1515	    cutlass::ComplexTransform::kNone,
1516	    8,
1517	    ElementB,
1518	    LayoutB,
1519	    cutlass::ComplexTransform::kNone,
1520	    8,
1521	    ElementOutput, LayoutC,
1522	    ElementAccumulator,
1523	    cutlass::arch::OpClassTensorOp,
1524	    cutlass::arch::Sm80,
1525	    cutlass::gemm::GemmShape<128, 128, 32>,
1526	    cutlass::gemm::GemmShape<64, 64, 32>,
1527	    cutlass::gemm::GemmShape<16, 8, 16>,
1528	    cutlass::epilogue::thread::LinearCombination<
1529	        ElementOutput, 128 / cutlass::sizeof_bits<ElementOutput>::value,
1530	        ElementAccumulator, ElementAccumulator>,
1531	    // NOTE: Threadblock swizzling is currently not supported by CUTLASS's grouped kernels.
1532	    // This parameter is passed in at present to match the APIs of other kernels. The parameter
1533	    // is unused within the kernel.
1534	    cutlass::gemm::threadblock::GemmBatchedIdentityThreadblockSwizzle,
1535	    4>::GemmKernel;
1536	
1537	  using GemmGrouped = cutlass::gemm::device::GemmGrouped<GemmKernel>;
1538	
1539	  //
1540	  // Profile it
1541	  //
1542	
1543	  TestbedBatched<GemmBatched> testbed_batched(options);
1544	  Result result = testbed_batched.profile();
1545	  if (result.error) {
1546	    return 1;
1547	  }
1548	
1549	  using GroupScheduleMode = cutlass::gemm::kernel::GroupScheduleMode;
1550	  for (GroupScheduleMode mode : options.scheduler_modes) {
